#include <bits/stdc++.h>
using namespace std;
int n,p,a,b,c[5000001]; 
int main(){
    cin>>n>>p;
    for(int i=1;i<=n;i++){
    	cin>>b;
    	c[i]=b-a;
    	a=b;
	}
	int x,y,z;
	for(int i=1;i<=p;i++){
		cin>>x>>y>>z;
		c[x]+=z;c[y+1]-=z;
	}
	int sum=0,m=2000000000;
	for(int i=1;i<=n;i++){
		sum+=c[i];
		if(sum<m)m=sum;
	}
	cout<<m;
    return 0;
}
